import{c as t,Q as a,j as n,m as s}from"./chunks/framework.iD28w_5a.js";const u=JSON.parse('{"title":"028e-activate-init-thread-1 · Init 线程","description":"","frontmatter":{"title":"028e-activate-init-thread-1 · Init 线程"},"headers":[],"relativePath":"hands-on/028e-activate-init-thread-1.md","filePath":"hands-on/028e-activate-init-thread-1.md","lastUpdated":1779686691000}'),i={name:"hands-on/028e-activate-init-thread-1.md"};function o(d,e,r,c,l,p){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="从-kernel-main-到-init-线程——内核启动架构重构" tabindex="-1">从 kernel_main 到 init 线程——内核启动架构重构 <a class="header-anchor" href="#从-kernel-main-到-init-线程——内核启动架构重构" aria-label="Permalink to &quot;从 kernel_main 到 init 线程——内核启动架构重构&quot;">​</a></h1><blockquote><p>标签：init thread, scheduler bootstrap, kernel thread, PID 0/1 前置：<a href="./028d-sync-safety-3">028d 同步安全</a></p></blockquote><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>到目前为止，我们的 <code>kernel_main()</code> 一直是「一条路走到黑」的单线程初始化流程——从串口、GDT、IDT 一直初始化到 AHCI、ext2、VFS，最后直接跳进用户态。说实话，这个方案在前面的 tag 里跑得还行，但随着调度器和进程系统越来越完善，我们逐渐发现一个严重的架构问题：所有 post-scheduler 的工作（文件系统挂载、shell 启动）都塞在 <code>kernel_main()</code> 或者 <code>run_concurrent_stress()</code> 里面，而此时调度器已经启动了——这意味着这些操作并不是在一个正规的 Task 上下文中执行的。</p><p>本章我们要做一件在 OS 开发中非常经典的事情：把 <code>kernel_main()</code> 的后期工作拆出来，放进一个独立的内核线程——我们叫它 <code>kernel_init_thread</code>，也就是 Linux 里的 <code>kernel_init</code> 的 Cinux 版本。完成这一步之后，我们的启动流程会变成：boot CPU 上下文变成 boot task（类似 Linux PID 0），init 线程负责文件系统和 shell（类似 PID 1），然后 kernel_main 进入 yield+hlt 空闲循环。这种分离是任何一个正经操作系统都会做的——让内核初始化和进程管理各司其职。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="为什么要引入-init-线程" tabindex="-1">为什么要引入 init 线程 <a class="header-anchor" href="#为什么要引入-init-线程" aria-label="Permalink to &quot;为什么要引入 init 线程&quot;">​</a></h3><p>在之前的 tag 中，我们的启动流程大概是这样的：<code>kernel_main()</code> 把所有硬件和子系统初始化完，然后调用 <code>run_concurrent_stress()</code>——这个函数会启动调度器、创建一堆压力测试线程、等它们跑完，最后调用 <code>launch_first_user()</code> 跳进用户态。问题在于，<code>launch_first_user()</code> 会创建一个假的 <code>static Task shell_task{}</code>，一个零初始化的 Task 结构体——没有内核栈、tid 是 0、不在任何运行队列里。这就像你伪造了一张身份证去银行办事，一开始看着没问题，但当系统尝试用这张身份证做一些需要真实身份信息的操作时，就会全线崩溃。</p><p>更深层的问题在于：我们的调度器设计假设所有正在运行的代码都有一个有效的 Task 上下文。当 <code>sys_exit</code> 被调用时，它会通过 <code>Scheduler::current()</code> 获取当前 Task 并将其标记为 Dead——但那个伪造的 shell_task 不在运行队列中，调度器根本不知道它的存在。如果调度器试图切回这个 Task，它会发现没有有效的 CPU 上下文，然后你就收获一个漂亮的 kernel panic。</p><h3 id="linux-的-init-模型" tabindex="-1">Linux 的 init 模型 <a class="header-anchor" href="#linux-的-init-模型" aria-label="Permalink to &quot;Linux 的 init 模型&quot;">​</a></h3><p>我们来看一下 Linux 是怎么做的。Linux 的 <code>start_kernel()</code> 相当于我们的 <code>kernel_main()</code>，它在单线程环境下完成所有早期硬件初始化。在 <code>start_kernel()</code> 的末尾，<code>rest_init()</code> 被调用，它做了三件事：首先，spawn <code>kernel_init</code> 内核线程（这将成为 PID 1）；其次，spawn <code>kthreadd</code> 内核线程（PID 2，负责管理后续所有内核线程）；最后，boot CPU 进入 idle 循环（PID 0）。<code>kernel_init</code> 线程负责完成剩余的驱动初始化、挂载根文件系统，然后尝试 exec <code>/sbin/init</code>（或 systemd）进入用户态。</p><p>这个模型的核心思想是：内核初始化分为「单线程早期初始化」和「可调度的后期初始化」两个阶段。早期初始化负责那些必须在 scheduler 运行前完成的工作（内存管理、中断控制器），后期初始化可以在 scheduler 管理下进行，享受抢占、同步等好处。我们现在要做的，就是把 Cinux 的后期初始化搬进一个 init 内核线程。</p><h3 id="boot-task-的角色" tabindex="-1">Boot Task 的角色 <a class="header-anchor" href="#boot-task-的角色" aria-label="Permalink to &quot;Boot Task 的角色&quot;">​</a></h3><p>在我们的设计中，<code>kernel_main()</code> 在调度器启动后创建一个 boot task，然后调用 <code>Scheduler::run_first(boot_task)</code> 开始调度。这个 boot task 的入口函数是一个简单的 halt 循环——理论上它永远不应该被执行到，因为 <code>run_first</code> 会立即 context-switch 到 kernel_init。boot task 的角色类似 Linux 的 PID 0 idle task：它是一个「占位符」，代表 boot CPU 的原始执行上下文被正式纳入调度器的管理之下。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-创建-init-线程声明" tabindex="-1">Step 1: 创建 init 线程声明 <a class="header-anchor" href="#step-1-创建-init-线程声明" aria-label="Permalink to &quot;Step 1: 创建 init 线程声明&quot;">​</a></h3><p><strong>目标</strong>: 新建一个头文件，声明 init 线程的入口函数。</p><p><strong>设计思路</strong>: init 线程的入口函数需要是一个无参数、无返回值的函数，和 <code>TaskBuilder::set_entry()</code> 接受的函数签名一致。我们把它放在 <code>kernel/proc/</code> 目录下，和调度器、进程管理代码放在一起——因为 init 线程本质上就是进程系统的一部分。</p><p><strong>实现约束</strong>: 头文件只需要一个简单的命名空间声明，不需要包含其他头文件。函数签名为 void(void)。</p><p><strong>验证</strong>: 头文件创建后，暂时无法单独验证。等后续步骤完成后一起编译。</p><h3 id="step-2-重构-kernel-main——调度器启动与线程创建" tabindex="-1">Step 2: 重构 kernel_main——调度器启动与线程创建 <a class="header-anchor" href="#step-2-重构-kernel-main——调度器启动与线程创建" aria-label="Permalink to &quot;Step 2: 重构 kernel_main——调度器启动与线程创建&quot;">​</a></h3><p><strong>目标</strong>: 修改 <code>kernel_main()</code> 的尾部，使其启动调度器、创建 init 线程和 boot task，然后进入 idle 循环。</p><p><strong>设计思路</strong>: 原来的 <code>kernel_main()</code> 在 AHCI 初始化之后直接做 ext2 挂载、VFS 注册、shell 启动。现在这些工作全部交给 init 线程。<code>kernel_main()</code> 的新职责变成了：初始化调度器，用 <code>TaskBuilder</code> 创建 kernel_init 线程并添加到运行队列，创建 boot task 并调用 <code>Scheduler::run_first()</code> 启动调度。</p><p><code>Scheduler::run_first()</code> 的语义很重要——它会把当前 CPU 上下文保存到 boot task 中，然后 context-switch 到运行队列中的第一个就绪任务（也就是 kernel_init）。从此以后，kernel_init 就在调度器的管理下运行了，而 boot CPU 的原始上下文变成了一个「休眠」的 Task。如果所有任务都退出了，<code>kernel_main()</code> 的最后会进入一个 yield + hlt 的空闲循环。</p><p><strong>实现约束</strong>: 需要注意以下几点——<code>Scheduler::init()</code> 必须在创建任何 Task 之前调用；<code>TaskBuilder</code> 的 <code>set_entry</code> 接受一个函数指针；<code>Scheduler::add_task</code> 把任务加入默认调度类的运行队列；<code>run_first</code> 启动第一次调度；boot task 的入口应该是一个死循环 hlt。</p><p><strong>踩坑预警</strong>: 如果你忘了 <code>Scheduler::init()</code> 直接创建 Task，会在 TaskBuilder::build 里因为空指针崩溃。另外，boot task 的 lambda 捕获要小心——不要捕获任何栈变量，因为 boot task 的 lambda 可能在 <code>kernel_main</code> 返回很久之后才被执行到（虽然理论上不应该被执行到）。</p><p><strong>验证</strong>: 构建并运行内核，检查串口输出。你应该看到类似这样的序列：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[BIG] ===== Scheduler &amp; Init Thread =====</span></span>
<span class="line"><span>[SCHED] Idle task created tid=1</span></span>
<span class="line"><span>[SCHED] Scheduler initialised with RoundRobin class</span></span>
<span class="line"><span>[PROC] Created task tid=2 name=&#39;kernel_init&#39; stack=0x...</span></span>
<span class="line"><span>[SCHED] Task tid=2 &#39;kernel_init&#39; added to RoundRobin</span></span>
<span class="line"><span>[PROC] Created task tid=3 name=&#39;boot&#39; stack=0x...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="step-3-删除旧的-stress-test" tabindex="-1">Step 3: 删除旧的 stress test <a class="header-anchor" href="#step-3-删除旧的-stress-test" aria-label="Permalink to &quot;Step 3: 删除旧的 stress test&quot;">​</a></h3><p><strong>目标</strong>: 移除 <code>kernel/stress/stress_test.cpp</code> 和整个 <code>kernel/stress/</code> 目录，同时更新 CMakeLists.txt。</p><p><strong>设计思路</strong>: stress test 是 028d 为了验证同步安全而写的临时测试代码。现在 init 线程模型已经就位，压力测试的职责完全可以由独立的测试程序来承担，不需要在内核启动流程中硬编码。删除 stress test 也简化了启动流程——从「先跑压力测试再启动 shell」变成了「直接启动 shell」。</p><p><strong>实现约束</strong>: CMakeLists.txt 中需要移除 stress_test.cpp 的编译项。同时删除 <code>kernel_main()</code> 中对 <code>run_concurrent_stress()</code> 的外部声明和调用。确认没有任何其他文件引用 stress test 的函数或变量。</p><p><strong>验证</strong>: 编译通过，链接没有报未定义引用。运行时不再看到 <code>[STRESS]</code> 相关的串口输出。</p><h3 id="step-4-实现-init-线程的框架" tabindex="-1">Step 4: 实现 init 线程的框架 <a class="header-anchor" href="#step-4-实现-init-线程的框架" aria-label="Permalink to &quot;Step 4: 实现 init 线程的框架&quot;">​</a></h3><p><strong>目标</strong>: 在 <code>kernel/proc/init.cpp</code> 中实现 <code>kernel_init_thread()</code> 的基本框架。</p><p><strong>设计思路</strong>: init 线程的核心工作有三步：挂载 ext2 文件系统、注册 VFS、启动第一个用户态程序。这三个步骤之前在 <code>kernel_main()</code> 中是直接调用的，现在只需要把它们搬到 init 线程里就行——但有一个关键区别：AHCI 实例不再是 <code>kernel_main()</code> 里的局部变量，而是通过 <code>AHCI::instance()</code> 单例获取。</p><p><strong>实现约束</strong>: init 线程需要包含 AHCI、ext2、VFS、usermode 等头文件。ext2 实例声明为 static 局部变量（和原来在 <code>kernel_main</code> 中一样）。挂载失败时打印错误日志但不崩溃——后续的 shell 启动可能会失败，但至少不会 kernel panic。init 线程的末尾调用 <code>Scheduler::exit_current()</code> 正常退出。</p><p><strong>踩坑预警</strong>: ext2 构造函数接受一个 AHCI 引用和端口号。使用 <code>AHCI::instance()</code> 返回引用时，确保 <code>set_instance()</code> 已经在 <code>kernel_main()</code> 中被调用过了。如果 init 线程跑得太快（在 <code>set_instance</code> 之前就被调度到了），你会得到一个空指针解引用。不过在我们的实现中，<code>set_instance()</code> 在 <code>Scheduler::init()</code> 之前就完成了，所以不会有这个问题。</p><p><strong>验证</strong>: 运行内核，检查串口输出中 <code>[INIT]</code> 前缀的日志。你应该看到 init 线程启动、ext2 挂载、VFS 初始化的完整序列。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>构建命令和之前一样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mkdir -p build &amp;&amp; cd build</span></span>
<span class="line"><span>cmake .. &amp;&amp; make -j$(nproc)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>运行 QEMU：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./run.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者直接：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>qemu-system-x86_64 -cdrom cinux.iso -serial stdio -no-reboot</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>最常见的问题：调度器启动后无输出</strong>。如果 <code>Scheduler::run_first()</code> 之后什么日志都看不到，最可能的原因是 init 线程的入口函数指针为空或者 TaskBuilder::build 返回了 nullptr。检查 <code>TaskBuilder::set_entry()</code> 是否正确传入了函数指针。</p><p><strong>第二个常见问题：init 线程中 AHCI 操作超时</strong>。如果看到 <code>[AHCI] Port X: command timeout</code>，那很可能是 MMIO 地址被覆盖了——这是本 tag 最关键的 bug，我们会在第三篇文章中详细讨论。暂时可以确认 <code>memory_layout.hpp</code> 中的各区域地址没有重叠。</p><p><strong>用串口辅助调试</strong>：所有 <code>[INIT]</code>、<code>[SCHED]</code>、<code>[PROC]</code> 前缀的日志都会输出到串口。如果 QEMU 窗口卡住了但串口还在输出，说明调度器在正常工作但显示可能有问题。如果串口也停了，大概率是 triple fault——用 <code>-d int</code> 参数运行 QEMU 查看异常信息。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td>init 线程</td><td>类似 Linux PID 1，负责 post-scheduler 初始化</td></tr><tr><td>boot task</td><td>类似 Linux PID 0 idle，boot CPU 上下文的占位符</td></tr><tr><td><code>Scheduler::run_first()</code></td><td>从 boot task context-switch 到第一个就绪任务</td></tr><tr><td><code>Scheduler::exit_current()</code></td><td>init 线程完成后的正常退出</td></tr><tr><td><code>AHCI::instance()</code></td><td>单例模式，解决跨翻译单元访问问题</td></tr></tbody></table><p>到这里，我们完成了内核启动架构的核心重构。但 init 线程目前还只是个框架——它里面 ext2 挂载和 shell 启动的具体细节，以及 <code>launch_first_user()</code> 的 shell_task 修复，我们留到下一章来完成。</p>`,53)])])}const k=t(i,[["render",o]]);export{u as __pageData,k as default};
